:root {
  --card-bg: #ffffff;
  --header-bg: #1a1a2e;
  --tag-bg: #e63946;
  --tag-color: #ffffff;
  --date-color: #a0a8c0;
  --headline-color: #1a1a2e;
  --subtext-color: #555e7a;
  --divider-color: #e2e6f0;
  --stat-value-color: #e63946;
  --stat-label-color: #8891aa;
  --footer-bg: #f0f2f8;
  --source-color: #555e7a;
  --pill-bg: #fff0c2;
  --pill-color: #7a5a00;
  --card-border: #d8dce8;
}

body {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  margin: 0;
  padding: 20px;
  box-sizing: border-box;
}

.card {
  background: var(--card-bg);
  border: 1.5px solid var(--card-border);
  border-radius: 14px;
  width: 480px;
  overflow: hidden;
}

.card-header {
  background: var(--header-bg);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 18px;
}

.tag {
  background: var(--tag-bg);
  color: var(--tag-color);
  font-size: 10px;
  font-weight: 800;
  letter-spacing: 1.5px;
  padding: 3px 9px;
  border-radius: 4px;
  text-transform: uppercase;
}

.date {
  color: var(--date-color);
  font-size: 12px;
  font-weight: 500;
}

.headline {
  color: var(--headline-color);
  font-size: 22px;
  font-weight: 800;
  line-height: 1.25;
  margin: 18px 18px 10px 18px;
  padding: 0;
}

.subtext {
  color: var(--subtext-color);
  font-size: 13px;
  line-height: 1.6;
  margin: 0 18px 16px 18px;
}

.divider {
  height: 1.5px;
  background: var(--divider-color);
  margin: 0 18px;
}

.stats-row {
  display: flex;
  justify-content: space-around;
  padding: 16px 18px;
}

.stat {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
}

.stat-value {
  color: var(--stat-value-color);
  font-size: 24px;
  font-weight: 800;
  line-height: 1;
}

.stat-label {
  color: var(--stat-label-color);
  font-size: 11px;
  font-weight: 500;
  text-align: center;
  letter-spacing: 0.3px;
}

.footer {
  background: var(--footer-bg);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 18px;
  border-top: 1.5px solid var(--divider-color);
}

.source {
  color: var(--source-color);
  font-size: 12px;
  font-weight: 600;
  font-style: italic;
}

.pill {
  background: var(--pill-bg);
  color: var(--pill-color);
  font-size: 11px;
  font-weight: 700;
  padding: 3px 10px;
  border-radius: 20px;
}
